import{_ as i,o as a,c as e,a5 as t}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：Boost C 固件骨架（Boost C Firmware Skeleton）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：Boost C 固件骨架（Boost C Firmware Skeleton）","tags":["power-electronics"],"status":"learning","summary":"Boost C 固件骨架是把前面 Python 里的控制中断服务程序（control interrupt service routine / control ISR）拆成接近工程阅读方式的 C 文件："},"headers":[],"relativePath":"content/power/concepts/embedded/boost-c-firmware-skeleton.md","filePath":"content/power/concepts/embedded/boost-c-firmware-skeleton.md","lastUpdated":null}'),l={name:"content/power/concepts/embedded/boost-c-firmware-skeleton.md"};function o(n,s,p,r,h,c){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="概念-boost-c-固件骨架-boost-c-firmware-skeleton" tabindex="-1">概念：Boost C 固件骨架（Boost C Firmware Skeleton） <a class="header-anchor" href="#概念-boost-c-固件骨架-boost-c-firmware-skeleton" aria-label="Permalink to &quot;概念：Boost C 固件骨架（Boost C Firmware Skeleton）&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>Boost C 固件骨架是把前面 Python 里的控制中断服务程序（control interrupt service routine / control ISR）拆成接近工程阅读方式的 C 文件：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ADC 采样 -&gt; 保护判断 -&gt; 控制 ISR -&gt; PWM 输出 -&gt; 状态机锁存</span></span></code></pre></div><p>它不是某个真实产品的软件，也不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）软件通常不是一个孤立控制公式，而是一组模块协同工作：</p><ul><li>模数转换器（analog-to-digital converter / ADC）读取电压电流。</li><li>保护（protection）判断过压、欠压、过流。</li><li>控制 ISR 计算占空比。</li><li>脉宽调制（pulse-width modulation / PWM）输出占空比或关断。</li><li>状态机（state machine）决定运行、故障、复位等模式。</li></ul><p>能看懂这些模块边界，比单独背一个比例积分控制器（proportional-integral controller / PI）公式更接近入职后的代码阅读任务。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>电源控制软件像一条有安全门的流水线。采样值先经过保护门，只有确认不危险，控制器才有资格更新 PWM。如果保护门发现过压，状态机会进入故障，并把 PWM 关断。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>核心逻辑可以写成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fault = Protection_Check(sample, config)</span></span>
<span class="line"><span>if fault != NONE:</span></span>
<span class="line"><span>    runtime.fault = fault</span></span>
<span class="line"><span>    runtime.state = FAULT</span></span>
<span class="line"><span>    duty = 0</span></span>
<span class="line"><span>else:</span></span>
<span class="line"><span>    error = Vref - Vout</span></span>
<span class="line"><span>    integrator = clamp(integrator + Ki * error * Ts)</span></span>
<span class="line"><span>    duty = clamp(Kp * error + integrator)</span></span></code></pre></div><p>这个顺序很重要：先保护，再控制，再输出。不要让危险采样值先经过控制器放大成新的 PWM 命令。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>这里的一个仿真任务是编译并运行可编译 C 教学程序，不驱动真实硬件。它用 <code>adc.c</code> 提供一组固定采样，其中 <code>tick=03</code> 控制周期出现过压：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gcc </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">std</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c99 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Wall </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Wextra </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Werror </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">I projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">boost</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\src projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">boost</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\src\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.c </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">boost</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">boost_c_firmware_skeleton.exe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">boost</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">boost_c_firmware_skeleton.exe</span></span></code></pre></div><p>观察输出里的 <code>state</code>、<code>fault</code>、<code>pwm</code>：</p><ul><li><code>RUN + NONE + pwm&gt;0</code>：允许控制输出。</li><li><code>FAULT + OVERVOLTAGE + pwm=0</code>：过压后锁存，PWM 关断。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实工程会更复杂，包括硬件抽象层（hardware abstraction layer / HAL）、中断向量、寄存器、定点数、通信任务和诊断日志。本教学骨架只保留最关键的阅读线索：</p><ul><li><code>control.c</code>：先看 <code>Boost_ControlIsr()</code>。</li><li><code>protection.c</code>：看故障码从哪里来。</li><li><code>pwm.c</code>：看正常占空比和强制关断的接口。</li><li><code>state_machine.c</code>：看故障如何进入 <code>FAULT</code> 状态。</li><li><code>boost_types.h</code>：看配置、采样、运行状态的结构体。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：C 工程就是把 Python 函数翻译成 C。<br> 正确理解：C 工程更强调模块边界、状态保存、实时调度和硬件接口。</p></li><li><p>错误理解：保护逻辑可以放在控制计算之后。<br> 正确理解：保护应优先阻断危险输出。</p></li><li><p>错误理解：PWM 关断只是把占空比设小一点。<br> 正确理解：严重故障下通常要明确调用关断路径，并由状态机控制复位条件。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能指出 <code>Boost_ControlIsr()</code> 的输入、状态、配置和输出。</li><li>能解释为什么 <code>Protection_Check()</code> 要在比例积分控制器（proportional-integral controller / PI）计算前执行。</li><li>能根据终端输出说明 <code>tick=03</code> 触发过压，<code>tick=04</code> 仍然故障锁存。</li><li>能解释 <code>Pwm_SetDuty()</code> 和 <code>Pwm_ForceOff()</code> 为什么要分成两个接口。</li><li>能基于 <code>control.c -&gt; Boost_ControlIsr()</code> 准备具体导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><code>tick=03</code> 的 <code>vout</code> 是多少？它和过压阈值是什么关系？</li><li>为什么 <code>tick=04</code> 的采样恢复后，状态仍然是 <code>FAULT</code>，<code>pwm</code> 仍然为 0？</li><li>如果真实工程把 <code>Protection_Check()</code> 放在 PI 计算之后，可能放大什么风险？</li><li><code>boost_types.h</code> 里为什么要把 <code>AdcSample</code>、<code>BoostConfig</code> 和 <code>BoostRuntime</code> 分开？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><p>提问时只带教学产物和自己的理解，不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><ul><li>我用 <code>projects/02-boost-c-firmware-skeleton/src/control.c</code> 看到 <code>Boost_ControlIsr()</code> 先保护再控制。公司代码里的 ISR 是否也是这种顺序？</li><li>我看到 <code>pwm.c</code> 同时有 <code>Pwm_SetDuty()</code> 和 <code>Pwm_ForceOff()</code>。真实工程里软件关断和硬件保护关断通常如何分工？</li><li>我看到 <code>boost_types.h</code> 把配置、采样、运行状态分开。公司工程里参数表、实时变量和故障状态通常放在哪些模块？</li></ul>`,32)])])}const E=i(l,[["render",o]]);export{k as __pageData,E as default};
